      }
      ... on NumericalSearchField {
        min
        max
        step
        unit
        defaultValue
      }
      ... on NumericalRangeSearchField {
        min
        max
        step
        unit
        defaultLower
        defaultUpper
      }
      ... on GeoSearchField {
        defaultLatitude
        defaultLongitude
        maxRadiusMiles
      }
