        }
        rankings {
          usNewsNational
          usNewsLiberalArts
          forbes
          washingtonMonthlyNational
          washingtonMonthlyLiberalArts
          niche
          moneyScore
        }
        admissions {
          applicationPlatforms
        }
        athletics {
          ncaaDivision
          ncaaConference
        }
        climate {
          koppenClimate
          koppenTemperature
