import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { Search } from './Search'

// useQuery is called twice per render: once for SearchFieldsQuery, once for SearchQuery.
// We dispatch on the operation name. In Vitest with vi.mock('urql'), args.query is the
// raw template string; in production it is a TypedDocumentNode. getOperationName handles both.
const { mockUseQuery } = vi.hoisted(() => ({ mockUseQuery: vi.fn() }))
vi.mock('urql', () => ({ useQuery: mockUseQuery }))
vi.mock('@/stores/preferencesStore', () => ({
  usePreferencesStore: (selector: (s: Record<string, unknown>) => unknown) =>
    selector({ homeLatitude: null, homeLongitude: null, homeState: null, loaded: false, loading: false, load: vi.fn(), update: vi.fn(), clear: vi.fn() }),
}))
vi.mock('@mantine/hooks', async () => {
  const actual = await vi.importActual('@mantine/hooks')
  return { ...actual, useMediaQuery: () => true }
})

function getOperationName(query: unknown): string {
  // In Vitest with vi.mock('urql'), args.query arrives as the raw template string.
  // In production (and some test environments), it is a DocumentNode.
  if (typeof query === 'string') {
    const match = query.match(/^\s*(?:query|mutation|subscription)\s+(\w+)/m)
    return match?.[1] ?? ''
  }
  if (typeof query !== 'object' || query === null) return ''
  const doc = query as { definitions?: Array<{ name?: { value?: string } }> }
  return doc.definitions?.[0]?.name?.value ?? ''
}

// ── Fixtures ───────────────────────────────────────────────────────────────────

const MOCK_OUTPUT_FIELDS = [
  { name: 'name', label: 'Name', theme: 'CORE', defaultVisible: true, exportable: true, sortable: false, unit: null, outputKey: null },
  { name: 'city', label: 'City', theme: 'CORE', defaultVisible: true, exportable: true, sortable: false, unit: null, outputKey: null },
  { name: 'state', label: 'State', theme: 'CORE', defaultVisible: true, exportable: true, sortable: false, unit: null, outputKey: null },
]

const MOCK_FIELDS = [
  {
    __typename: 'TextSearchField',
    name: 'name',
    label: 'Institution Name',
    description: 'Full-text search on institution name',
    theme: 'CORE',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: true,
  },
  {
    __typename: 'BinarySearchField',
    name: 'hbcu',
    label: 'HBCU',
    description: 'Historically Black Colleges and Universities',
    theme: 'ACADEMICS',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: false,
  },
  {
    __typename: 'ChoiceSearchField',
    name: 'control',
    label: 'Control',
    description: 'Institution control type',
    theme: 'CORE',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: false,
    options: [
      { value: '1', displayName: 'Public' },
      { value: '2', displayName: 'Private nonprofit' },
      { value: '3', displayName: 'Private for-profit' },
    ],
    minSelections: 0,
    maxSelections: 1,
  },
  {
    __typename: 'ChoiceSearchField',
    name: 'application_platforms',
    label: 'Application Platforms',
    description: 'Platforms through which applications are accepted',
    theme: 'ADMISSIONS',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: false,
    options: [
      { value: 'common_app', displayName: 'Common App' },
      { value: 'coalition', displayName: 'Coalition' },
      { value: 'apply_texas', displayName: 'Apply Texas' },
    ],
    minSelections: 0,
    maxSelections: null,
  },
  {
    __typename: 'ChoiceSearchField',
    name: 'state',
    label: 'State',
    description: 'US state where the institution is located',
    theme: 'LOCATION',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: true,
    options: [
      { value: 'AL', displayName: 'Alabama' },
      { value: 'AK', displayName: 'Alaska' },
      { value: 'AZ', displayName: 'Arizona' },
      { value: 'CA', displayName: 'California' },
      { value: 'CO', displayName: 'Colorado' },
      { value: 'CT', displayName: 'Connecticut' },
      { value: 'FL', displayName: 'Florida' },
      { value: 'GA', displayName: 'Georgia' },
    ],
    minSelections: 0,
    maxSelections: null,
  },
  {
    __typename: 'NumericalSearchField',
    name: 'tuition',
    label: 'Tuition',
    description: 'Annual tuition cost',
    theme: 'COST',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: true,
    unit: 'DOLLARS',
    min: 0,
    max: 80000,
    step: 1000,
  },
  {
    __typename: 'GeoSearchField',
    name: 'location',
    label: 'Location',
    description: 'Geographic proximity',
    theme: 'LOCATION',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: false,
    maxRadiusMiles: 100,
  },
  {
    __typename: 'TextSearchField',
    name: 'hidden_field',
    label: 'Hidden Field',
    description: 'Should not render in the sidebar',
    theme: 'OTHER',
    visibility: 'HIDDEN',
    searchability: 'SEARCHABLE',
    exportable: false,
  },
  {
    __typename: 'TextSearchField',
    name: 'city',
    label: 'City',
    description: 'City where the institution is located',
    theme: 'LOCATION',
    visibility: 'VISIBLE',
    searchability: 'NOT_SEARCHABLE',
    exportable: true,
  },
]

const MOCK_SEARCH_DATA = {
  search: {
    results: [
      { unitID: '166683', name: 'MIT', city: 'Cambridge', state: 'MA' },
      { unitID: '130794', name: 'Harvard University', city: 'Cambridge', state: 'MA' },
    ],
    total: 2,
    limit: 20,
    offset: 0,
  },
}

// ── Mock setup ─────────────────────────────────────────────────────────────────

function setupMocks(
  fieldsOverride?: Record<string, unknown>,
  searchOverride?: Record<string, unknown>,
) {
  const fieldsState = {
    fetching: false,
    data: { searchFields: MOCK_FIELDS },
    error: undefined,
    ...fieldsOverride,
  }
  const searchState = {
    fetching: false,
    data: MOCK_SEARCH_DATA,
    error: undefined,
    ...searchOverride,
  }
  const outputFieldsState = {
    fetching: false,
    data: { searchOutputFields: MOCK_OUTPUT_FIELDS },
    error: undefined,
  }
  const detailState = {
    fetching: false,
    data: { institution: null },
    error: undefined,
  }
  const dataSourcesState = {
    fetching: false,
    data: { dataSources: [] },
    error: undefined,
  }
  mockUseQuery.mockImplementation((args: { query: unknown }) => {
    const opName = getOperationName(args.query)
    if (opName === 'SearchFields') {
      return [fieldsState, vi.fn()]
    }
    if (opName === 'SearchOutputFields') {
      return [outputFieldsState, vi.fn()]
    }
    if (opName === 'InstitutionDetail') {
      return [detailState, vi.fn()]
    }
    if (opName === 'DataSources') {
      return [dataSourcesState, vi.fn()]
    }
    return [searchState, vi.fn()]
  })
}

function renderSearch(initialEntry = '/search') {
  return render(
    <MemoryRouter initialEntries={[initialEntry]}>
      <MantineProvider>
        <Search />
      </MantineProvider>
    </MemoryRouter>,
  )
}

// ── Tests ──────────────────────────────────────────────────────────────────────

describe('Search', () => {
  beforeEach(() => {
    mockUseQuery.mockReset()
    localStorage.clear()
    setupMocks()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  it('renders the filter sidebar and results heading', () => {
    renderSearch()
    expect(screen.getByText(/filters/i)).toBeInTheDocument()
    expect(screen.getByRole('heading', { name: /results/i })).toBeInTheDocument()
  })

  it('shows a loading indicator while field metadata is fetching', () => {
    setupMocks({ fetching: true, data: undefined })
    renderSearch()
    expect(screen.getByText(/loading filters/i)).toBeInTheDocument()
  })

  it('shows an error message when field metadata fails to load', () => {
    setupMocks({ fetching: false, data: undefined, error: new Error('network error') })
    renderSearch()
    expect(screen.getByText(/failed to load filters/i)).toBeInTheDocument()
  })

  it('renders a text input for TextSearchField', () => {
    renderSearch()
    expect(screen.getByRole('textbox', { name: /institution name/i })).toBeInTheDocument()
  })

  it('renders a checkbox for BinarySearchField', () => {
    renderSearch()
    expect(screen.getByRole('checkbox', { name: /hbcu/i })).toBeInTheDocument()
  })

  it('renders geo filter inputs for GeoSearchField', () => {
    renderSearch()
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toBeInTheDocument()
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toBeInTheDocument()
  })

  it('renders a <select> for a ChoiceSearchField with maxSelections === 1', () => {
    renderSearch()
    const select = screen.getByRole('combobox', { name: /control/i })
    expect(select).toBeInTheDocument()
    expect(select.tagName).toBe('SELECT')
    // 3 options + the "Any" placeholder
    expect(select.querySelectorAll('option')).toHaveLength(4)
  })

  it('renders checkboxes for a ChoiceSearchField with maxSelections === null', () => {
    renderSearch()
    expect(screen.getByRole('checkbox', { name: /common app/i })).toBeInTheDocument()
    expect(screen.getByRole('checkbox', { name: /coalition/i })).toBeInTheDocument()
    expect(screen.getByRole('checkbox', { name: /apply texas/i })).toBeInTheDocument()
  })

  it('selecting a <select> option sets a SingleEnumFilter', async () => {
    const user = userEvent.setup()
    renderSearch()
    const select = screen.getByRole('combobox', { name: /control/i })
    await user.selectOptions(select, '1')
    expect(select).toHaveValue('1')
  })

  it('checking a multi-select checkbox sets a MultiEnumFilter', async () => {
    const user = userEvent.setup()
    renderSearch()
    const checkbox = screen.getByRole('checkbox', { name: /common app/i })
    await user.click(checkbox)
    expect(checkbox).toBeChecked()
  })

  it('unchecking a multi-select checkbox removes the value from the filter', async () => {
    const user = userEvent.setup()
    renderSearch()
    const checkbox = screen.getByRole('checkbox', { name: /common app/i })
    await user.click(checkbox)
    expect(checkbox).toBeChecked()
    await user.click(checkbox)
    expect(checkbox).not.toBeChecked()
  })

  it('does not render HIDDEN fields in the sidebar', () => {
    renderSearch()
    expect(screen.queryByText('Hidden Field')).not.toBeInTheDocument()
  })

  it('renders NOT_SEARCHABLE fields as display-only with no filter control', () => {
    renderSearch()
    // "City" appears in both the filter sidebar and table header
    expect(screen.getAllByText('City').length).toBeGreaterThan(0)
    expect(screen.getAllByText(/display only/i).length).toBeGreaterThan(0)
  })

  it('renders search results with institution name, city, and state', () => {
    renderSearch()
    expect(screen.getByText('MIT')).toBeInTheDocument()
    expect(screen.getByText('Harvard University')).toBeInTheDocument()
    // Default card view renders city, state together
    expect(screen.getAllByText('Cambridge, MA').length).toBeGreaterThan(0)
  })

  it('opens institution detail modal when clicking a result card', async () => {
    const user = userEvent.setup()
    renderSearch()
    await user.click(screen.getByText('MIT'))
    expect(screen.getByRole('dialog')).toBeInTheDocument()
  })

  it('shows loading skeletons while search is fetching', () => {
    setupMocks(undefined, { fetching: true, data: undefined })
    renderSearch()
    expect(screen.getByTestId('results-loading')).toBeInTheDocument()
    expect(screen.getAllByTestId('result-skeleton')).toHaveLength(3)
  })

  it('shows empty state with "Clear all filters" button when total is 0', () => {
    setupMocks(undefined, {
      data: { search: { results: [], total: 0, limit: 20, offset: 0 } },
    })
    renderSearch()
    expect(screen.getByText(/no colleges match your filters/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /clear all filters/i })).toBeInTheDocument()
  })

  it('shows error state with retry button on search error', () => {
    setupMocks(undefined, { fetching: false, data: undefined, error: new Error('fail') })
    renderSearch()
    expect(screen.getByText(/something went wrong/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /retry/i })).toBeInTheDocument()
  })

  it('shows "Showing X–Y of Z" result count text', () => {
    renderSearch()
    expect(screen.getByText(/showing 1–2 of 2 institutions found/i)).toBeInTheDocument()
  })

  it('accepts typed text in a TextSearchField input', async () => {
    const user = userEvent.setup()
    renderSearch()
    const input = screen.getByRole('textbox', { name: /institution name/i })
    await user.type(input, 'MIT')
    expect(input).toHaveValue('MIT')
  })

  it('pre-populates the name filter from the ?q= URL parameter', () => {
    renderSearch('/search?q=MIT')
    const input = screen.getByRole('textbox', { name: /institution name/i })
    expect(input).toHaveValue('MIT')
  })

  it('toggles a BinarySearchField checkbox', async () => {
    const user = userEvent.setup()
    renderSearch()
    const checkbox = screen.getByRole('checkbox', { name: /hbcu/i })
    expect(checkbox).not.toBeChecked()
    await user.click(checkbox)
    expect(checkbox).toBeChecked()
  })

  // ── URL param persistence ───────────────────────────────────────────────────

  it('restores a text filter from URL params on mount', () => {
    renderSearch('/search?name=Stanford')
    const input = screen.getByRole('textbox', { name: /institution name/i })
    expect(input).toHaveValue('Stanford')
  })

  it('restores a binary filter from URL params on mount', () => {
    renderSearch('/search?hbcu=1')
    const checkbox = screen.getByRole('checkbox', { name: /hbcu/i })
    expect(checkbox).toBeChecked()
  })

  it('restores a single-select filter from URL params on mount', () => {
    renderSearch('/search?control=2')
    const select = screen.getByRole('combobox', { name: /control/i })
    expect(select).toHaveValue('2')
  })

  it('restores a multi-select filter from URL params on mount', () => {
    renderSearch('/search?application_platforms=common_app,coalition')
    expect(screen.getByRole('checkbox', { name: /common app/i })).toBeChecked()
    expect(screen.getByRole('checkbox', { name: /coalition/i })).toBeChecked()
    expect(screen.getByRole('checkbox', { name: /apply texas/i })).not.toBeChecked()
  })

  it('restores multiple filters from URL params on mount', () => {
    renderSearch('/search?name=MIT&hbcu=1&control=1')
    expect(screen.getByRole('textbox', { name: /institution name/i })).toHaveValue('MIT')
    expect(screen.getByRole('checkbox', { name: /hbcu/i })).toBeChecked()
    expect(screen.getByRole('combobox', { name: /control/i })).toHaveValue('1')
  })

  it('ignores unknown URL params that do not match any field', () => {
    renderSearch('/search?bogus=xyz&name=MIT')
    expect(screen.getByRole('textbox', { name: /institution name/i })).toHaveValue('MIT')
  })

  // ── Multi-select threshold (inline vs scalable) ─────────────────────────────

  it('renders inline checkboxes without a filter input for multi-select with fewer than 6 options', () => {
    renderSearch()
    // application_platforms has 3 options → inline checkboxes, no filter input
    expect(screen.getByRole('checkbox', { name: /common app/i })).toBeInTheDocument()
    expect(screen.queryByLabelText(/filter application platforms options/i)).not.toBeInTheDocument()
  })

  it('renders a filter input for multi-select with 6 or more options', () => {
    renderSearch()
    // state has 8 options → scalable UI with filter input
    expect(screen.getByLabelText(/filter state options/i)).toBeInTheDocument()
  })

  it('filters options when typing in the multi-select filter input', async () => {
    const user = userEvent.setup()
    renderSearch()
    const filterInput = screen.getByLabelText(/filter state options/i)
    await user.type(filterInput, 'cal')
    // Only California should be visible
    expect(screen.getByText('California')).toBeInTheDocument()
    expect(screen.queryByText('Alabama')).not.toBeInTheDocument()
    expect(screen.queryByText('Alaska')).not.toBeInTheDocument()
  })

  it('shows "No matching options" when filter text matches nothing', async () => {
    const user = userEvent.setup()
    renderSearch()
    const filterInput = screen.getByLabelText(/filter state options/i)
    await user.type(filterInput, 'zzz')
    expect(screen.getByText(/no matching options/i)).toBeInTheDocument()
  })

  // ── Tooltip descriptions ───────────────────────────────────────────────────

  it('shows field description in a tooltip when hovering the info icon', async () => {
    const user = userEvent.setup()
    renderSearch()
    const infoButton = screen.getByRole('button', { name: /info about institution name/i })
    expect(infoButton).toBeInTheDocument()
    await user.hover(infoButton)
    expect(await screen.findByRole('tooltip')).toHaveTextContent(
      'Full-text search on institution name',
    )
  })

  it('renders info icons for fields with descriptions', () => {
    renderSearch()
    // All visible fields have descriptions in MOCK_FIELDS
    expect(screen.getByRole('button', { name: /info about institution name/i })).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /info about hbcu/i })).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /info about control/i })).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /info about tuition/i })).toBeInTheDocument()
  })

  it('preserves the name filter from ?q= when selecting another facet', async () => {
    const user = userEvent.setup()
    renderSearch('/search?q=MIT')
    const nameInput = screen.getByRole('textbox', { name: /institution name/i })
    expect(nameInput).toHaveValue('MIT')

    // Select a different filter — name should be preserved
    const select = screen.getByRole('combobox', { name: /control/i })
    await user.selectOptions(select, '1')

    expect(nameInput).toHaveValue('MIT')
    expect(select).toHaveValue('1')
  })

  // ── Pagination ──────────────────────────────────────────────────────────────

  it('does not render pagination controls when results fit in one page', () => {
    renderSearch()
    expect(screen.queryByTestId('pagination-controls')).not.toBeInTheDocument()
  })

  it('renders pagination controls when total exceeds page size', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: Array.from({ length: 20 }, (_, i) => ({
            unitID: String(i),
            name: `School ${i}`,
            city: 'City',
            state: 'ST',
          })),
          total: 80,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch()
    expect(screen.getByTestId('pagination-controls')).toBeInTheDocument()
  })

  it('renders page size selector with correct options', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: Array.from({ length: 20 }, (_, i) => ({
            unitID: String(i),
            name: `School ${i}`,
            city: 'City',
            state: 'ST',
          })),
          total: 80,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch()
    const pageSizeSelect = screen.getByLabelText(/per page/i)
    expect(pageSizeSelect).toBeInTheDocument()
    const options = pageSizeSelect.querySelectorAll('option')
    expect(options).toHaveLength(5)
    expect(Array.from(options).map((o) => o.value)).toEqual(['5', '10', '20', '50', '100'])
  })

  it('reads page and pageSize from URL params on mount', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [{ unitID: '1', name: 'School 1', city: 'City', state: 'ST' }],
          total: 50,
          limit: 10,
          offset: 10,
        },
      },
    })
    renderSearch('/search?page=2&pageSize=10')
    // Verify the query was called with the right variables
    const lastCall = mockUseQuery.mock.calls.find(
      (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
        getOperationName(call[0].query) === 'Search',
    )
    expect(lastCall).toBeDefined()
    expect(lastCall![0].variables).toEqual(
      expect.objectContaining({ limit: 10, offset: 10 }),
    )
  })

  it('shows "100+ results" indicator when total exceeds 100', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: Array.from({ length: 20 }, (_, i) => ({
            unitID: String(i),
            name: `School ${i}`,
            city: 'City',
            state: 'ST',
          })),
          total: 500,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch()
    expect(screen.getByText(/100\+ results/i)).toBeInTheDocument()
  })

  // ── Location, distance, and myPrice ────────────────────────────────────────

  it('renders LocationInput in the sidebar', () => {
    renderSearch()
    expect(screen.getByText(/your location/i)).toBeInTheDocument()
    expect(screen.getByPlaceholderText('e.g. 02134')).toBeInTheDocument()
  })

  it('shows distance column when userLocation is in URL params', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: 42.3, myPrice: null },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search?userLat=42.0&userLng=-72.0')
    expect(screen.getByTestId('distance')).toHaveTextContent('42 mi')
  })

  it('shows "< 1 mi" for very short distances', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: 0.3, myPrice: null },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search?userLat=42.0&userLng=-72.0')
    expect(screen.getByTestId('distance')).toHaveTextContent('< 1 mi')
  })

  it('shows myPrice column when userLocation has state', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: 10, myPrice: 15000 },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search?userLat=42.0&userLng=-72.0&userState=MA')
    expect(screen.getByTestId('my-price')).toHaveTextContent('$15,000')
  })

  it('does not show distance column when no userLocation', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: null, myPrice: null },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch()
    expect(screen.queryByTestId('distance')).not.toBeInTheDocument()
  })

