/**
 * ESLint rule: no-raw-graphql-strings
 *
 * Prevents raw template-literal or string-literal GraphQL queries.
 * All queries must use graphql() from gql.tada for compile-time schema validation.
 *
 * Flags template literals and string literals whose content starts with
 * "query ", "mutation ", "subscription ", or "fragment " (after trimming).
 *
 * Allows:
 *   import { graphql } from 'gql.tada'
 *   const MyQuery = graphql(`query Foo { ... }`)
 *
 * Disallows:
 *   const MyQuery = `query Foo { ... }`
 *   const MyQuery = "query Foo { ... }"
 */

const GRAPHQL_PATTERN = /^\s*(query|mutation|subscription|fragment)\s/

const message =
  'Raw GraphQL strings are not allowed. Use graphql() from gql.tada for compile-time schema validation. ' +
  'See web/CLAUDE.md for details.'

/** @type {import('eslint').Rule.RuleModule} */
export default {
  meta: {
    type: 'problem',
    docs: {
      description: 'Disallow raw GraphQL query strings; require gql.tada graphql()',
    },
    schema: [],
    messages: {
      noRawGraphQL: message,
    },
  },
  create(context) {
    function isInsideGraphqlCall(node) {
      // Allow: graphql(`query ...`) — the tagged template or call expression from gql.tada
      const parent = node.parent
      if (!parent) return false
      // graphql(`...`) as a call expression argument
      if (
        parent.type === 'CallExpression' &&
        parent.callee.type === 'Identifier' &&
        parent.callee.name === 'graphql'
      ) {
        return true
      }
      return false
    }

    return {
      TemplateLiteral(node) {
        if (isInsideGraphqlCall(node)) return
        // Only check simple template literals (no expressions)
        if (node.expressions.length > 0) return
        const text = node.quasis[0]?.value?.raw ?? ''
        if (GRAPHQL_PATTERN.test(text)) {
          context.report({ node, messageId: 'noRawGraphQL' })
        }
      },
      Literal(node) {
        if (typeof node.value !== 'string') return
        if (GRAPHQL_PATTERN.test(node.value)) {
          context.report({ node, messageId: 'noRawGraphQL' })
        }
      },
    }
  },
}

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { renderHook } from '@testing-library/react'
import { useWebMCP } from './useWebMCP'

describe('useWebMCP', () => {
  let registerToolSpy: ReturnType<typeof vi.fn>
  let constructorSpy: ReturnType<typeof vi.fn>

  beforeEach(() => {
    registerToolSpy = vi.fn()
    constructorSpy = vi.fn()

    window.WebMCP = class {
      registerTool = registerToolSpy
      constructor(options: Record<string, unknown>) {
        constructorSpy(options)
      }
    } as unknown as typeof window.WebMCP
  })

  afterEach(() => {
    delete window.WebMCP
  })

  it('creates a WebMCP instance with brand color and position', () => {
    renderHook(() => useWebMCP())

    expect(constructorSpy).toHaveBeenCalledOnce()
    expect(constructorSpy).toHaveBeenCalledWith({
      color: '#c9a227',
      position: 'bottom-right',
    })
  })

  it('registers search_colleges and get_search_fields tools', () => {
    renderHook(() => useWebMCP())

    expect(registerToolSpy).toHaveBeenCalledTimes(2)

    const toolNames = registerToolSpy.mock.calls.map(
      (call: unknown[]) => call[0] as string,
    )
    expect(toolNames).toContain('search_colleges')
    expect(toolNames).toContain('get_search_fields')
  })

  it('does not re-initialize on re-render', () => {
    const { rerender } = renderHook(() => useWebMCP())
    rerender()
    rerender()

    expect(constructorSpy).toHaveBeenCalledOnce()
  })

  it('does nothing when WebMCP is not available on window', () => {
    delete window.WebMCP
    renderHook(() => useWebMCP())

    expect(constructorSpy).not.toHaveBeenCalled()
    expect(registerToolSpy).not.toHaveBeenCalled()
  })

  it('registers search_colleges with correct schema shape', () => {
    renderHook(() => useWebMCP())

    const searchCall = registerToolSpy.mock.calls.find(
      (call: unknown[]) => call[0] === 'search_colleges',
    )
    expect(searchCall).toBeDefined()

    const schema = searchCall![2] as Record<string, unknown>
    expect(schema.type).toBe('object')
    expect(schema.properties).toHaveProperty('filters')
    expect(schema.properties).toHaveProperty('limit')
    expect(schema.properties).toHaveProperty('offset')
  })

  it('registers get_search_fields with empty properties schema', () => {
    renderHook(() => useWebMCP())

    const fieldsCall = registerToolSpy.mock.calls.find(
      (call: unknown[]) => call[0] === 'get_search_fields',
    )
    expect(fieldsCall).toBeDefined()

    const schema = fieldsCall![2] as { properties: Record<string, unknown> }
    expect(Object.keys(schema.properties)).toHaveLength(0)
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'

const mockQuery = vi.fn()
const mockMutation = vi.fn()

vi.mock('@/lib/urqlClient', () => ({
  urqlClient: {
    query: (...args: unknown[]) => ({ toPromise: () => mockQuery(...args) }),
    mutation: (...args: unknown[]) => ({ toPromise: () => mockMutation(...args) }),
  },
}))

describe('preferencesStore', () => {
  beforeEach(async () => {
    vi.resetModules()
    mockQuery.mockReset()
    mockMutation.mockReset()
  })

  async function getStore() {
    const { usePreferencesStore } = await import('./preferencesStore')
    return usePreferencesStore
  }

  it('has correct initial state', async () => {
    const store = await getStore()
    const state = store.getState()
    expect(state.homeLatitude).toBeNull()
    expect(state.homeLongitude).toBeNull()
    expect(state.homeState).toBeNull()
    expect(state.loaded).toBe(false)
    expect(state.loading).toBe(false)
  })

  it('load fetches and stores preferences', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: {
          homeLatitude: 40.7128,
          homeLongitude: -74.006,
          homeState: 'NY',
        },
      },
    })
    const store = await getStore()

    await store.getState().load()

    const state = store.getState()
    expect(state.homeLatitude).toBe(40.7128)
    expect(state.homeLongitude).toBe(-74.006)
    expect(state.homeState).toBe('NY')
    expect(state.loaded).toBe(true)
    expect(state.loading).toBe(false)
  })

  it('load skips if already loaded', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: { homeLatitude: 40.7, homeLongitude: -74.0, homeState: 'NY' },
      },
    })
    const store = await getStore()

    await store.getState().load()
    await store.getState().load()

    expect(mockQuery).toHaveBeenCalledOnce()
  })

  it('load handles null preferences gracefully', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: { homeLatitude: null, homeLongitude: null, homeState: null },
      },
    })
    const store = await getStore()

    await store.getState().load()

    const state = store.getState()
    expect(state.homeLatitude).toBeNull()
    expect(state.homeLongitude).toBeNull()
    expect(state.homeState).toBeNull()
    expect(state.loaded).toBe(true)
  })

  it('update sends mutation and updates state', async () => {
    mockMutation.mockResolvedValue({
      data: {
        updatePreferences: {
          homeLatitude: 34.05,
          homeLongitude: -118.24,
          homeState: 'CA',
        },
      },
    })
    const store = await getStore()

    await store.getState().update({
      homeLatitude: 34.05,
      homeLongitude: -118.24,
      homeState: 'CA',
    })

    const state = store.getState()
    expect(state.homeLatitude).toBe(34.05)
    expect(state.homeLongitude).toBe(-118.24)
    expect(state.homeState).toBe('CA')
  })

  it('clear resets all state', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: { homeLatitude: 40.7, homeLongitude: -74.0, homeState: 'NY' },
      },
    })
    const store = await getStore()

    await store.getState().load()
    store.getState().clear()

    const state = store.getState()
    expect(state.homeLatitude).toBeNull()
    expect(state.homeLongitude).toBeNull()
    expect(state.homeState).toBeNull()
    expect(state.loaded).toBe(false)
    expect(state.loading).toBe(false)
  })
})

