import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MantineProvider } from '@mantine/core'
import { LocationInput, type UserLocationValue } from './LocationInput'

const { mockUseQuery } = vi.hoisted(() => ({ mockUseQuery: vi.fn() }))
vi.mock('urql', () => ({ useQuery: mockUseQuery }))

function renderLocationInput(
  value: UserLocationValue | undefined = undefined,
  onChange = vi.fn(),
) {
  return {
    onChange,
    ...render(
      <MantineProvider>
        <LocationInput value={value} onChange={onChange} />
      </MantineProvider>,
    ),
  }
}

describe('LocationInput', () => {
  beforeEach(() => {
    mockUseQuery.mockReset()
    mockUseQuery.mockReturnValue([{ fetching: false, data: undefined, error: undefined }, vi.fn()])
  })

  it('renders ZIP code input and geolocation button when no value', () => {
    renderLocationInput()
    expect(screen.getByPlaceholderText('e.g. 02134')).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /use my location/i })).toBeInTheDocument()
  })

  it('shows display name and clear button when value is set', () => {
    renderLocationInput({
      latitude: 42.0,
      longitude: -72.0,
      state: 'MA',
      displayName: 'Amherst, MA',
    })
    expect(screen.getByText('Amherst, MA')).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /clear location/i })).toBeInTheDocument()
  })

  it('calls onChange(undefined) when clear button is clicked', async () => {
    const user = userEvent.setup()
    const { onChange } = renderLocationInput({
      latitude: 42.0,
      longitude: -72.0,
      displayName: 'Amherst, MA',
    })
    await user.click(screen.getByRole('button', { name: /clear location/i }))
    expect(onChange).toHaveBeenCalledWith(undefined)
  })

  it('shows error for invalid ZIP format', async () => {
    const user = userEvent.setup()
    renderLocationInput()
    const input = screen.getByPlaceholderText('e.g. 02134')
    await user.type(input, '123')
    await user.click(screen.getByRole('button', { name: 'Go' }))
    expect(screen.getByText(/5-digit ZIP code/i)).toBeInTheDocument()
  })

  it('resolves ZIP and calls onChange on success', async () => {
    const user = userEvent.setup()
    mockUseQuery.mockReturnValue([
      {
        fetching: false,
        data: {
          resolveZip: {
            zip: '02134',
            latitude: 42.35,
            longitude: -71.13,
            state: 'MA',
            city: 'Allston',
          },
        },
        error: undefined,
      },
      vi.fn(),
    ])
    const { onChange } = renderLocationInput()
    const input = screen.getByPlaceholderText('e.g. 02134')
    await user.type(input, '02134')
    await user.click(screen.getByRole('button', { name: 'Go' }))
    expect(onChange).toHaveBeenCalledWith({
      latitude: 42.35,
      longitude: -71.13,
      state: 'MA',
      displayName: 'Allston, MA',
    })
  })

  it('shows error when ZIP not found', async () => {
    const user = userEvent.setup()
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { resolveZip: null }, error: undefined },
      vi.fn(),
    ])
    const { onChange } = renderLocationInput()
    const input = screen.getByPlaceholderText('e.g. 02134')
    await user.type(input, '00000')
    await user.click(screen.getByRole('button', { name: 'Go' }))
    expect(screen.getByText(/ZIP code not found/i)).toBeInTheDocument()
    expect(onChange).not.toHaveBeenCalled()
  })

  it('calls geolocation API when "Use my location" is clicked', async () => {
    const user = userEvent.setup()
    const mockGetPosition = vi.fn((success: PositionCallback) => {
      success({
        coords: { latitude: 42.36, longitude: -71.06, accuracy: 10 },
      } as GeolocationPosition)
    })
    Object.defineProperty(navigator, 'geolocation', {
      value: { getCurrentPosition: mockGetPosition },
      writable: true,
    })

    const { onChange } = renderLocationInput()
    await user.click(screen.getByRole('button', { name: /use my location/i }))
    expect(mockGetPosition).toHaveBeenCalled()
    expect(onChange).toHaveBeenCalledWith(
      expect.objectContaining({
        latitude: 42.36,
        longitude: -71.06,
      }),
    )
  })

  it('shows coordinates as display name when no displayName provided', () => {
    renderLocationInput({
      latitude: 42.36,
      longitude: -71.06,
    })
    expect(screen.getByText('42.36°, -71.06°')).toBeInTheDocument()
  })
})

