  latitude: 42.36,
  longitude: -71.09,
  institutionType: '2',
  enrollment: 11574,
  graduationRate: 0.94,
  admissionRate: 0.04,
  inStateTuition: 57590,
  outOfStateTuition: 57590,
  avgNetPrice: 21642,
  retentionRate: 0.99,
  studentFacultyRatio: 3,
}

function renderDetail(props: Partial<Parameters<typeof InstitutionDetail>[0]> = {}) {
  return render(
    <MantineProvider>
      <InstitutionDetail
        unitID="166683"
        opened={true}
        onClose={vi.fn()}
        {...props}
      />
    </MantineProvider>,
  )
}

describe('InstitutionDetail', () => {
  beforeEach(() => {
    mockUseQuery.mockReset()
  })

  it('shows a loader while fetching', () => {
    mockUseQuery.mockReturnValue([{ fetching: true, data: undefined, error: undefined }, vi.fn()])
    renderDetail()
    expect(screen.getByRole('dialog')).toBeInTheDocument()
    const dialog = screen.getByRole('dialog')
    expect(dialog.querySelector('.mantine-Loader-root')).toBeInTheDocument()
  })

  it('shows an error message on query failure', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: undefined, error: new Error('network') },
      vi.fn(),
    ])
    renderDetail()
    expect(screen.getByText(/failed to load institution details/i)).toBeInTheDocument()
  })

  it('renders institution details when data is loaded', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { institution: MOCK_INSTITUTION }, error: undefined },
      vi.fn(),
    ])
    renderDetail()
    // MIT appears in both modal title and body
    expect(screen.getAllByText('MIT').length).toBeGreaterThanOrEqual(1)
    expect(screen.getByText('Cambridge, MA')).toBeInTheDocument()
    expect(screen.getByText('Private nonprofit')).toBeInTheDocument()
    expect(screen.getByText('11,574')).toBeInTheDocument()
    expect(screen.getByText('3:1')).toBeInTheDocument()
    // In-state and out-of-state tuition are both $57,590
    expect(screen.getAllByText('$57,590').length).toBe(2)
    expect(screen.getByText('$21,642')).toBeInTheDocument()
    expect(screen.getByText('4.0%')).toBeInTheDocument()
    expect(screen.getByText('94.0%')).toBeInTheDocument()
    expect(screen.getByText('99.0%')).toBeInTheDocument()
  })

  it('shows "Institution not found" when institution is null', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { institution: null }, error: undefined },
      vi.fn(),
    ])
    renderDetail()
    expect(screen.getByText(/institution not found/i)).toBeInTheDocument()
  })

  it('pauses the query when unitID is null', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: undefined, error: undefined },
      vi.fn(),
    ])
    renderDetail({ unitID: null })
    expect(mockUseQuery).toHaveBeenCalledWith(
      expect.objectContaining({ pause: true }),
    )
  })

  it('renders dashes for null optional fields', () => {
    const partialInst = {
      ...MOCK_INSTITUTION,
      enrollment: null,
      admissionRate: null,
      inStateTuition: null,
      studentFacultyRatio: null,
    }
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { institution: partialInst }, error: undefined },
      vi.fn(),
    ])
    renderDetail()
    // Should show dashes for null fields
    const dashes = screen.getAllByText('—')
    expect(dashes.length).toBeGreaterThanOrEqual(4)
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import { renderWithMantine } from '@/test/render'
import { SimilarInstitutions } from './SimilarInstitutions'

const mockSimilarInstitutions = [
  {
    unitID: '111111',
    name: 'Similar University',
    city: 'Springfield',
    state: 'IL',
    distance: 0.15,
    institutionType: '1',
    enrollment: 5000,
    admissionRate: 0.65,
    graduationRate: 0.7,
    inStateTuition: 12000,
    outOfStateTuition: 25000,
  },
  {
    unitID: '222222',
    name: 'Another College',
    city: 'Portland',
    state: 'OR',
    distance: 0.25,
    institutionType: '2',
    enrollment: 3000,
    admissionRate: 0.5,
    graduationRate: 0.8,
    inStateTuition: 45000,
    outOfStateTuition: 45000,
  },
]

let mockUseQuery: ReturnType<typeof vi.fn>

vi.mock('urql', () => ({
  useQuery: (...args: unknown[]) => mockUseQuery(...args),
}))

beforeEach(() => {
  mockUseQuery = vi.fn()
})

describe('SimilarInstitutions', () => {
  it('shows loading state', () => {
    mockUseQuery.mockReturnValue([{ fetching: true, data: undefined, error: undefined }])
    const { container } = renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(container.querySelector('.mantine-Loader-root')).toBeInTheDocument()
  })

  it('shows error state', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: undefined, error: new Error('Network error') },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(screen.getByText('Failed to load similar institutions.')).toBeInTheDocument()
  })

  it('shows empty state when no results', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { similarInstitutions: [] }, error: undefined },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(screen.getByText('No similar institutions found.')).toBeInTheDocument()
  })

  it('renders similar institutions', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { similarInstitutions: mockSimilarInstitutions }, error: undefined },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(screen.getByText('Similar University')).toBeInTheDocument()
    expect(screen.getByText('Springfield, IL')).toBeInTheDocument()
    expect(screen.getByText('Another College')).toBeInTheDocument()
    expect(screen.getByText('Portland, OR')).toBeInTheDocument()
  })

  it('displays institution type badges', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { similarInstitutions: mockSimilarInstitutions }, error: undefined },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(screen.getByText('Public')).toBeInTheDocument()
    expect(screen.getByText('Private nonprofit')).toBeInTheDocument()
  })

  it('displays enrollment badges', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { similarInstitutions: mockSimilarInstitutions }, error: undefined },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(screen.getByText('5,000 students')).toBeInTheDocument()
    expect(screen.getByText('3,000 students')).toBeInTheDocument()
  })

  it('displays admission and graduation rates', () => {
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { similarInstitutions: mockSimilarInstitutions }, error: undefined },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" />)
    expect(screen.getByText('Admit: 65%')).toBeInTheDocument()
    expect(screen.getByText('Grad: 70%')).toBeInTheDocument()
  })

  it('calls onSelect when card is clicked', async () => {
    const { userEvent } = await import('@testing-library/user-event')
    const user = userEvent.setup()
    const onSelect = vi.fn()
    mockUseQuery.mockReturnValue([
      { fetching: false, data: { similarInstitutions: mockSimilarInstitutions }, error: undefined },
    ])
    renderWithMantine(<SimilarInstitutions unitID="123456" onSelect={onSelect} />)
    await user.click(screen.getByText('Similar University'))
    expect(onSelect).toHaveBeenCalledWith('111111')
  })

  it('passes correct variables to query', () => {
    mockUseQuery.mockReturnValue([{ fetching: true, data: undefined, error: undefined }])
    renderWithMantine(<SimilarInstitutions unitID="999999" />)
    expect(mockUseQuery).toHaveBeenCalledWith(
      expect.objectContaining({
        variables: { unitID: '999999', limit: 6 },
      }),
    )
  })
})
